import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const navigate = useNavigate();

    useEffect(() => {
        const fetchLeads = async () => {
            const token = localStorage.getItem("token");
            try {
                const res = await axios.get("http://localhost:8000/leads", {
                    headers: { Authorization: `Bearer ${token}` },
                });
                setLeads(res.data);
            } catch (err) {
                console.error("Error fetching leads:", err);
                if (err.response && err.response.status === 401) {
                    setError("Session expired. Please log in again.");
                    localStorage.removeItem("token");
                    localStorage.removeItem("role");
                    navigate("/"); // Redirect to login
                } else {
                    setError("Failed to load leads. Please try again later.");
                }
            } finally {
                setLoading(false);
            }
        };
        fetchLeads();
    }, [navigate]);

    if (loading) return <p className="text-center mt-4">Loading leads...</p>;

    if (error) return <p className="text-danger text-center mt-4">{error}</p>;

    return (
        <div className="container mt-4">
            <h2 className="mb-3">Leads</h2>
            {leads.length > 0 ? (
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            {/* {Object.keys(leads[0]).map((col) => (
                                <th key={col}>{col}</th>
                            ))} */}
                            ID
                        </tr>
                        <tr>Name</tr>
                        <tr>User Name</tr>
                        <tr>Email</tr>
                        <tr>Phone</tr>
                        <tr>Company URL</tr>
                        <tr>Company Name</tr>
                    </thead>
                    <tbody>
                        {leads.map((lead, idx) => (
                            <tr key={idx}>
                                {Object.values(lead).map((val, i) => (
                                    <td key={i}>{val}</td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p className="text-muted">No leads found.</p>
            )}
        </div>
    );
}

export default Leads;
